    <script>
        // ========== St会将$1替换成实际XML内容 ==========
        const exampleXML = `<char_status>$1</char_status>`;

        // ========== 解析XML数据 ==========
        function parseXML(xmlText) {
            console.log("开始解析角色状态...");
            const result = {
                basicInfo: {},
                characterData: {},
                inventory: []
            };

            try {
                // 提取基本信息
                const basicMatch = xmlText.match(/<basic_info>([\s\S]*?)<\/basic_info>/i);
                if (basicMatch && basicMatch[1]) {
                    const text = basicMatch[1].trim();

                    const timeMatch = text.match(/\[当前时间\|([^\]]+)\]/);
                    if (timeMatch) result.basicInfo.time = timeMatch[1];

                    const placeMatch = text.match(/\[当前地点\|([^\]]+)\]/);
                    if (placeMatch) result.basicInfo.place = placeMatch[1];
                }

                // 提取角色数据
                const charMatch = xmlText.match(/<character_data>([\s\S]*?)<\/character_data>/i);
                if (charMatch && charMatch[1]) {
                    const text = charMatch[1].trim();

                    const favorMatch = text.match(/\[好感度\|([^\]]+)\]/);
                    if (favorMatch) result.characterData.favor = favorMatch[1];

                    const levelMatch = text.match(/\[等级\|([^\]]+)\]/);
                    if (levelMatch) result.characterData.level = levelMatch[1];

                    const expMatch = text.match(/\[经验值\|([^\]]+)\]/);
                    if (expMatch && expMatch[1]) {
                        const parts = expMatch[1].split('|');
                        result.characterData.currentExp = parts[0] || '0';
                        result.characterData.maxExp = parts[1] || '100';
                    }
                }

                // 提取背包物品
                const invMatch = xmlText.match(/<inventory>([\s\S]*?)<\/inventory>/i);
                if (invMatch && invMatch[1]) {
                    const text = invMatch[1].trim();
                    const regex = /\[物品\|([^\]]+)\]/g;
                    let match;

                    while ((match = regex.exec(text)) !== null) {
                        if (match[1]) {
                            const parts = match[1].split('|');
                            if (parts[0] && parts[0] !== '无') {
                                result.inventory.push({
                                    name: parts[0] || '',
                                    count: parts[1] || '1'
                                });
                            }
                        }
                    }
                }

                console.log("解析完成:", result);
                return result;
            } catch (error) {
                console.error('解析错误:', error);
                return result;
            }
        }

        // ========== 渲染界面 ==========
        function renderPage(data) {
            console.log("开始渲染界面...");

            const expPercent = data.characterData.currentExp && data.characterData.maxExp
                ? (parseInt(data.characterData.currentExp) / parseInt(data.characterData.maxExp) * 100)
                : 0;

            let html = `
                <div class="header">
                    <div class="title">⚔️ 角色状态</div>
                </div>

                <div class="info-section">
                    <div class="section-title">📍 基本信息</div>
